import{c as t,Q as n,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Zeuik's Claude Code Docs","text":"Claude Code Harness 工程課程","tagline":"從 CLAUDE.md 設計到 Planner-Generator-Evaluator 架構，掌握讓 AI Agent 真正可靠的工程方法。","actions":[{"theme":"brand","text":"開始學習 →","link":"/lectures/lecture-01-foundations/"},{"theme":"alt","text":"實作專案","link":"/projects/"},{"theme":"alt","text":"GitHub ↗","link":"https://github.com/zeuikli/cc-workspace-docs"}]},"features":[{"icon":"🧠","title":"Harness 工程理論","details":"深入理解 Agent = Model + Body + Harness 等式。量化數據證明：同一個 Opus 4.6，不同 Harness 造成 13pp 效能差距。"},{"icon":"📄","title":"CLAUDE.md 設計實踐","details":"掌握四層作用域（managed policy / project / user / local），遵循 Ratchet 原則讓每行規則追蹤到具體失敗。"},{"icon":"🔄","title":"Context Engineering","details":"理解 Context Rot 機制（18 個模型全部隨 context 增長下降），學會用 Sub-agent 作為 Context Firewall 的結構性解法。"},{"icon":"🏗️","title":"三層 Harness 架構","details":"Planner / Generator / Evaluator 分離設計。為什麼 Generator 不能自評？25 種 Hooks 事件如何構建防禦層？"},{"icon":"💾","title":"記憶系統設計","details":"CLAUDE.md vs Auto Memory 兩種系統的差異與協同。Git Worktrees 實現多工作區並行，Skills 與 MCP Server 延伸能力。"},{"icon":"🔒","title":"安全沙箱工程","details":"macOS Seatbelt / Linux bubblewrap 的 OS 層隔離原理。Filesystem + Network 雙重隔離缺一不可。細粒度 Permission 設定指南。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1779800848000}`),i={name:"index.md"};function o(l,e,s,d,c,h){return n(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="關於本課程" tabindex="-1">關於本課程 <a class="header-anchor" href="#關於本課程" aria-label="Permalink to &quot;關於本課程&quot;">​</a></h2><p>本課程源自 <strong>Zeuik 的私有 cc-workspace</strong>，整理了 SRE / Cloud Architect 視角下對 Claude Code Workspace 的深度研究，涵蓋：</p><ul><li>1,200+ 篇論文、技術文章、工程實踐筆記</li><li>25 篇深度研究報告（Agent Harness、Token 優化、記憶架構等）</li><li>86 篇 arXiv 論文分析</li></ul><p>課程以 <strong>Harness Engineering</strong> 為主軸，從理論到實作，幫助你將 Claude Code 等 AI Agent 從「不可靠」變為「生產可用」。</p><h2 id="適合誰閱讀" tabindex="-1">適合誰閱讀 <a class="header-anchor" href="#適合誰閱讀" aria-label="Permalink to &quot;適合誰閱讀&quot;">​</a></h2><ul><li>想讓 Claude Code / Codex 在真實專案中可靠工作的工程師</li><li>對 LLM Agent 架構設計感興趣的開發者</li><li>希望系統化整理 AI 輔助開發最佳實踐的技術主管</li></ul><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>階段</th><th>內容</th><th>預估時間</th></tr></thead><tbody><tr><td>基礎理論</td><td>Lecture 01–02：認識 Harness，設計 CLAUDE.md</td><td>2 小時</td></tr><tr><td>核心架構</td><td>Lecture 03–04：Context Engineering + 三層 Harness</td><td>3 小時</td></tr><tr><td>進階實踐</td><td>Lecture 05–06：記憶系統 + 安全沙箱</td><td>2 小時</td></tr><tr><td>動手實作</td><td>Project 01–02：從零建立 Workspace + 設計 Harness</td><td>4 小時</td></tr></tbody></table><h2 id="關鍵參考資料" tabindex="-1">關鍵參考資料 <a class="header-anchor" href="#關鍵參考資料" aria-label="Permalink to &quot;關鍵參考資料&quot;">​</a></h2><blockquote><p>本課程的理論基礎來自以下官方資料：</p></blockquote><ul><li><a href="https://openai.com/index/harness-engineering/" target="_blank" rel="noreferrer">OpenAI: Harness engineering — leveraging Codex in an agent-first world</a></li><li><a href="https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents" target="_blank" rel="noreferrer">Anthropic: Effective harnesses for long-running agents</a></li><li><a href="https://www.anthropic.com/engineering/harness-design-long-running-apps" target="_blank" rel="noreferrer">Anthropic: Harness design for long-running application development</a></li><li><a href="https://www.langchain.com/blog/improving-deep-agents-with-harness-engineering" target="_blank" rel="noreferrer">LangChain: Improving Deep Agents with harness engineering</a></li></ul>',11)])])}const p=t(i,[["render",o]]);export{u as __pageData,p as default};
